import React from 'react';
import { View, Text } from 'react-native';
import { OAuth2 } from 'oauth2-client';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      accessToken: null,
    };
  }

  componentDidMount() {
    const oauth = new OAuth2({
      clientId,
      clientSecret,
      authorizationUrl: 'https://example.com/oauth/authorize',
      tokenUrl: 'https://example.com/oauth/token',
    });

    oauth.getAccessToken().then((accessToken) => {
      this.setState({ accessToken });
    }).catch((error) => {
      console.log(error);
    });
  }

  render() {
    return (
      <View>
        <Text>{this.state.accessToken}</Text>
      </View>
    );
  }
}